VALUES
('ph-foundations', NULL, 1, 'phase', NULL, NULL, NULL, 'Data Engineering Foundations', 'Core programming, command line, Git, SQL, Linux, and data engineering role fundamentals.', 'Phase grouping for Data Engineering Foundations.', 'trunk', 'roadmap-main', 1, 1, NULL, NULL, 100, 500, 520, '{"source": "roadmap.sh/data-engineer", "nodeKey": "ph-foundations"}'::jsonb, true, false, '["Data Engineering Foundations"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('grp-role-foundations', 'ph-foundations', 1, 'choice_group', NULL, 'complete_all', NULL, 'Data Engineering Role and Workflow', 'Data Engineering Role and Workflow groups related data engineering topics.', 'Data Engineering Role and Workflow groups related data engineering topics.', 'side', 'ph-foundations-groups', 1, 1, NULL, NULL, 90, 300, 380, '{"progressRule": "complete_all", "source": "roadmap.sh/data-engineer", "nodeKey": "grp-role-foundations"}'::jsonb, true, false, '["Data Engineering Role and Workflow"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('data-engineering-role', 'grp-role-foundations', 1, 'topic', NULL, NULL, NULL, 'Data Engineering Role', 'Understand what data engineers build: ingestion, storage, transformation, orchestration, quality, governance, and production data platforms.', 'Data Engineering Role is a concrete data engineering roadmap topic.', 'choice', 'grp-role-foundations-topics', 1, 1, 1, 'beginner', 80, 120, 570, '{"source": "roadmap.sh/data-engineer", "nodeKey": "data-engineering-role"}'::jsonb, true, true, '["Explain how Data Engineering Role affects practical data engineering work.", "Apply Data Engineering Role to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Data Engineering Role in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('data-lifecycle', 'grp-role-foundations', 2, 'topic', NULL, NULL, NULL, 'Data Lifecycle', 'Understand raw, staged, modeled, served, archived, and governed data across analytics and operational systems.', 'Data Lifecycle is a concrete data engineering roadmap topic.', 'choice', 'grp-role-foundations-topics', 1, 2, 2, 'beginner', 80, 330, 570, '{"source": "roadmap.sh/data-engineer", "nodeKey": "data-lifecycle"}'::jsonb, true, true, '["Explain how Data Lifecycle affects practical data engineering work.", "Apply Data Lifecycle to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Data Lifecycle in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('requirements-and-data-contract-thinking', 'grp-role-foundations', 3, 'topic', NULL, NULL, NULL, 'Requirements and Data Contract Thinking', 'Translate downstream data needs into source assumptions, schemas, freshness expectations, and acceptance criteria.', 'Requirements and Data Contract Thinking is a concrete data engineering roadmap topic.', 'choice', 'grp-role-foundations-topics', 1, 3, 2, 'intermediate', 80, 540, 570, '{"source": "roadmap.sh/data-engineer", "nodeKey": "requirements-and-data-contract-thinking"}'::jsonb, true, true, '["Explain how Requirements and Data Contract Thinking affects practical data engineering work.", "Apply Requirements and Data Contract Thinking to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Requirements and Data Contract Thinking in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('grp-dev-tools', 'ph-foundations', 2, 'choice_group', NULL, 'complete_all', NULL, 'Developer Tools', 'Developer Tools groups related data engineering topics.', 'Developer Tools groups related data engineering topics.', 'side', 'ph-foundations-groups', 2, 2, NULL, NULL, 90, 700, 510, '{"progressRule": "complete_all", "source": "roadmap.sh/data-engineer", "nodeKey": "grp-dev-tools"}'::jsonb, true, false, '["Developer Tools"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('linux-shell', 'grp-dev-tools', 1, 'topic', NULL, NULL, NULL, 'Linux Shell and CLI', 'Navigate files, inspect logs, pipe commands, manage environment variables, and automate routine tasks.', 'Linux Shell and CLI is a concrete data engineering roadmap topic.', 'choice', 'grp-dev-tools-topics', 2, 1, 2, 'beginner', 80, 120, 700, '{"source": "roadmap.sh/data-engineer", "nodeKey": "linux-shell"}'::jsonb, true, true, '["Explain how Linux Shell and CLI affects practical data engineering work.", "Apply Linux Shell and CLI to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Linux Shell and CLI in context.", "Use the concept to build or review a small UI behavior.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('git-collaboration', 'grp-dev-tools', 2, 'topic', NULL, NULL, NULL, 'Git and Pull Request Workflow', 'Use branches, commits, pull requests, review feedback, and conflict resolution for data projects.', 'Git and Pull Request Workflow is a concrete data engineering roadmap topic.', 'choice', 'grp-dev-tools-topics', 2, 2, 2, 'beginner', 80, 330, 700, '{"source": "roadmap.sh/data-engineer", "nodeKey": "git-collaboration"}'::jsonb, true, true, '["Explain how Git and Pull Request Workflow affects practical data engineering work.", "Apply Git and Pull Request Workflow to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Git and Pull Request Workflow in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('python-programming', 'grp-dev-tools', 3, 'topic', NULL, NULL, NULL, 'Python Programming', 'Write maintainable Python scripts, functions, modules, virtual environments, and error handling for data workflows.', 'Python Programming is a concrete data engineering roadmap topic.', 'choice', 'grp-dev-tools-topics', 2, 3, 6, 'beginner', 80, 540, 700, '{"source": "roadmap.sh/data-engineer", "nodeKey": "python-programming"}'::jsonb, true, true, '["Explain how Python Programming affects practical data engineering work.", "Apply Python Programming to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Python Programming in context.", "Use the concept to produce a small applied example or decision note.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('grp-sql-core', 'ph-foundations', 3, 'choice_group', NULL, 'complete_all', NULL, 'SQL Core', 'SQL Core groups related data engineering topics.', 'SQL Core groups related data engineering topics.', 'side', 'ph-foundations-groups', 3, 3, NULL, NULL, 90, 300, 640, '{"progressRule": "complete_all", "source": "roadmap.sh/data-engineer", "nodeKey": "grp-sql-core"}'::jsonb, true, false, '["SQL Core"]'::jsonb, '["Required child topics are completed"]'::jsonb),
('sql-querying', 'grp-sql-core', 1, 'topic', NULL, NULL, NULL, 'SQL Querying', 'Use SELECT, WHERE, JOIN, GROUP BY, HAVING, window functions, CTEs, and set operations.', 'SQL Querying is a concrete data engineering roadmap topic.', 'choice', 'grp-sql-core-topics', 3, 1, 6, 'beginner', 80, 120, 830, '{"source": "roadmap.sh/data-engineer", "nodeKey": "sql-querying"}'::jsonb, true, true, '["Explain how SQL Querying affects practical data engineering work.", "Apply SQL Querying to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining SQL Querying in context.", "Use the concept to produce a small query, schema, or validation example.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('sql-analytics-patterns', 'grp-sql-core', 2, 'topic', NULL, NULL, NULL, 'SQL Analytics Patterns', 'Build cohort, funnel, retention, deduplication, ranking, and time-series queries.', 'SQL Analytics Patterns is a concrete data engineering roadmap topic.', 'choice', 'grp-sql-core-topics', 3, 2, 4, 'intermediate', 80, 330, 830, '{"source": "roadmap.sh/data-engineer", "nodeKey": "sql-analytics-patterns"}'::jsonb, true, true, '["Explain how SQL Analytics Patterns affects practical data engineering work.", "Apply SQL Analytics Patterns to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining SQL Analytics Patterns in context.", "Use the concept to produce a small query, schema, or validation example.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('relational-database-basics', 'grp-sql-core', 3, 'topic', NULL, NULL, NULL, 'Relational Database Basics', 'Understand tables, keys, constraints, indexes, transactions, isolation, and query planning basics.', 'Relational Database Basics is a concrete data engineering roadmap topic.', 'choice', 'grp-sql-core-topics', 3, 3, 4, 'beginner', 80, 540, 830, '{"source": "roadmap.sh/data-engineer", "nodeKey": "relational-database-basics"}'::jsonb, true, true, '["Explain how Relational Database Basics affects practical data engineering work.", "Apply Relational Database Basics to build data pipeline components or evaluate an implementation decision.", "Identify common mistakes, trade-offs, and signals that the approach is working."]'::jsonb, '["Create concise notes or a diagram explaining Relational Database Basics in context.", "Use the concept to produce a small query, schema, or validation example.", "Explain at least two trade-offs, risks, or debugging signals related to the topic."]'::jsonb),
('gate-foundation-review', 'ph-foundations', 81, 'checkpoint', 'gate', NULL, NULL, 'Foundation Review Gate', 'Review checkpoint for Data Engineering Foundations. The learner consolidates evidence from Data Engineering Role, Data Lifecycle, Requirements and Data Contract Thinking, Linux Shell and CLI, identifies unresolved prerequisite gaps, and decides whether to continue, review selected topics, or complete extra practice before the next roadmap segment.', 'This checkpoint acts as a transition gate for the data engineering roadmap. It supports reflection and planning; it is not a certification, mastery test, or claim of job readiness.', 'checkpoint', 'ph-foundations-gates', 99, 81, 1, 'beginner', 85, 300, 910, '{"checkpoint": true, "source": "roadmap.sh/data-engineer", "nodeKey": "gate-foundation-review", "checkpointPurpose": "phase_review", "reviewMode": "gate", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Summarize the main concepts and decisions from Data Engineering Foundations in practical data engineering terms.", "Identify prerequisite gaps, unclear topics, or risks that should be reviewed before moving forward.", "Create a short evidence artifact that links completed roadmap items to what was learned."]'::jsonb, '["List the roadmap items reviewed for this checkpoint.", "Provide one evidence artifact such as notes, a diagram, a lab result, code, queries, screenshots, or a project review.", "Record at least two gaps, risks, or follow-up actions, or explicitly state that no critical gaps were found.", "Use the result to choose one next step: continue, review selected topics, or complete extra practice."]'::jsonb),
