('gate-final-review', 'ph-portfolio-career', 81, 'checkpoint', 'gate', NULL, NULL, 'Final Data Engineering Review Gate', 'Final roadmap checkpoint for Portfolio, Interview Readiness, and Capstone. The learner reviews portfolio evidence, unresolved gaps, and next learning priorities across the data engineering path.', 'This checkpoint closes the suggested data engineering orientation path by organizing evidence and next steps. It is not an employment guarantee or formal competency certification.', 'checkpoint', 'ph-portfolio-career-gates', 99, 81, 1, 'intermediate', 85, 300, 10030, '{"checkpoint": true, "source": "roadmap.sh/data-engineer", "nodeKey": "gate-final-review", "checkpointPurpose": "phase_review", "reviewMode": "final_review", "evidenceRequired": true, "claimLimit": "orientation_and_progress_review_only_not_certification"}'::jsonb, true, true, '["Connect completed roadmap work to a coherent data engineering learning narrative.", "Review portfolio or project evidence and identify which artifacts are ready to share.", "Define remaining gaps and future specialization priorities."]'::jsonb, '["Summarize completed phases, projects, and major skill groups.", "Attach or reference portfolio evidence, project links, diagrams, reports, tests, or notes where available.", "List remaining gaps or specialization topics for future learning.", "State that the checkpoint is a planning review, not proof of job readiness."]'::jsonb),
('proj-capstone-data-platform', 'ph-portfolio-career', 91, 'project', NULL, NULL, NULL, 'Required Data Engineering Capstone Project', 'Build a production-style data platform: ingestion, storage, orchestration, transformation, quality tests, warehouse/lakehouse tables, observability, docs, and deployment notes.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 91, 16, 'advanced', 75, 700, 10060, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-capstone-data-platform"}'::jsonb, true, true, '["Build Required Data Engineering Capstone Project", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb),
('proj-portfolio-package', 'ph-portfolio-career', 92, 'project', NULL, NULL, NULL, 'Required Portfolio Final Package', 'Polish the capstone with README, diagrams, runbook, data model docs, screenshots, sample queries, and known tradeoffs.', 'Project nodes are practice-heavy. Mini-projects are optional; milestone projects are required.', 'checkpoint', 'ph-portfolio-career-projects', 100, 92, 4, 'intermediate', 75, 700, 10140, '{"project": true, "optionalPractice": false, "source": "roadmap.sh/data-engineer", "nodeKey": "proj-portfolio-package"}'::jsonb, true, true, '["Build Required Portfolio Final Package", "Produce portfolio-ready evidence"]'::jsonb, '["Working pipeline or design exists", "README explains setup and tradeoffs", "Core behavior is tested or manually verified"]'::jsonb);
